import{_ as t,o,c as a,a2 as i}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"SDK stability & semver policy","description":"","frontmatter":{"docSection":"app-developers","docType":"policy","audiences":["app-developer","contributor"]},"headers":[],"relativePath":"sdk-stability.md","filePath":"sdk-stability.md"}'),s={name:"sdk-stability.md"};function d(r,e,n,c,l,p){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="sdk-stability-semver-policy" tabindex="-1">SDK stability &amp; semver policy <a class="header-anchor" href="#sdk-stability-semver-policy" aria-label="Permalink to &quot;SDK stability &amp; semver policy&quot;">​</a></h1><p><code>@sovereignfs/sdk</code> is the <strong>only</strong> contract between a plugin and the Sovereign platform. From <strong>v1.0.0</strong> it is a stable, semver-governed public API: plugin authors can depend on it without fear of silent breakage. This document defines what &quot;stable&quot; means and which parts of the surface the guarantee covers.</p><h2 id="semver-policy-nfr-04" tabindex="-1">Semver policy (NFR-04) <a class="header-anchor" href="#semver-policy-nfr-04" aria-label="Permalink to &quot;Semver policy (NFR-04)&quot;">​</a></h2><p><code>@sovereignfs/sdk</code> follows <a href="https://semver.org" target="_blank" rel="noreferrer">Semantic Versioning</a>:</p><table tabindex="0"><thead><tr><th>Bump</th><th>Means</th></tr></thead><tbody><tr><td><strong>patch</strong> (<code>1.0.x</code>)</td><td>Bug fixes and internal changes. <strong>No breaking changes, ever.</strong></td></tr><tr><td><strong>minor</strong> (<code>1.x.0</code>)</td><td><strong>Additive only</strong> — new methods/types/fields. Existing code keeps working.</td></tr><tr><td><strong>major</strong> (<code>x.0.0</code>)</td><td>Breaking changes, accompanied by a migration guide in <a href="./upgrade.html"><code>docs/upgrade.md</code></a>.</td></tr></tbody></table><p>The same discipline applies to <code>@sovereignfs/ui</code> (the design system is also a published plugin contract). Changes are recorded in each package&#39;s <code>CHANGELOG.md</code>.</p><h2 id="what-the-guarantee-covers" tabindex="-1">What the guarantee covers <a class="header-anchor" href="#what-the-guarantee-covers" aria-label="Permalink to &quot;What the guarantee covers&quot;">​</a></h2><p><strong>Stable surface</strong> — covered by the semver guarantee above:</p><ul><li><code>sdk.auth</code> — session and account (<code>getSession</code>, <code>requireSession</code>, <code>changePassword</code>, <code>listSessions</code>, <code>revokeSession</code>, <code>signOut</code>, <code>hasCapability(session, capability)</code>).</li><li><code>sdk.db</code> — the Drizzle client for this plugin&#39;s database (<code>getClient</code>). Returns the platform DB for <code>shared</code> plugins (the default) and a dedicated Drizzle instance for <code>isolated</code> plugins — transparent to the caller. See <a href="./plugin-database.html"><code>docs/plugin-database.md</code></a>.</li><li><code>sdk.mailer</code> — transactional email (<code>send</code>).</li><li><code>sdk.platform</code> — instance configuration (<code>getConfig</code>).</li></ul><p>Plus the exported types (<code>Session</code>, <code>SessionUser</code>, <code>ActiveSession</code>, <code>ChangePasswordInput</code>, <code>MailOptions</code>, <code>PlatformConfig</code>, <code>DrizzleClient</code>, …) and errors (<code>NotAuthenticatedError</code>, <code>NotImplementedError</code>, <code>ConsentRequiredError</code>).</p><h2 id="what-is-not-covered-experimental-reserved" tabindex="-1">What is NOT covered (experimental / reserved) <a class="header-anchor" href="#what-is-not-covered-experimental-reserved" aria-label="Permalink to &quot;What is NOT covered (experimental / reserved)&quot;">​</a></h2><p>These surfaces are <strong>experimental</strong> — they are implemented and usable, but their shape may still change before v1.0.0 stable. Changes follow the same minor/major bump discipline as stable surfaces, but an additive change (e.g. a new field on a callback argument) may ship without a minor bump in this group during the pre-v1 hardening period:</p><ul><li><code>sdk.data</code> — consent-gated cross-plugin data sharing (RFC 0002).</li><li><code>sdk.activity</code> — activity log (RFC 0005).</li><li><code>sdk.portability</code> — user data export/import (RFC 0007, <code>data:export</code>/<code>data:import</code> permissions).</li><li><code>sdk.env</code> — plugin-scoped environment variable accessor (RFC 0018). <code>sdk.env.get(key)</code> reads <code>SV_PLUGIN_&lt;SLUG&gt;_&lt;KEY&gt;</code> scoped to the calling plugin; server-side only.</li><li><code>sdk.notifications</code> — Notification Center (RFC 0015). <code>sdk.notifications.send()</code> delivers in-app notifications to users; requires the <code>notifications:send</code> manifest permission. Polling default (30s), SSE optional.</li><li><code>sdk.directory</code> — member search and explicit user resolution for display-safe user selection (RFC 0041).</li><li><code>sdk.secrets</code> — encrypted runtime-created plugin secrets (RFC 0043). Values are server-side only; list/export surfaces expose metadata only.</li><li><code>sdk.storage</code> — plugin-scoped binary object storage (RFC 0044). Local filesystem storage is implemented; future backends may expand the host implementation without changing plugin calls.</li><li><code>sdk.connections</code> — external provider connection metadata, OAuth state helpers, and server-side effective provider config reads (RFC 0049). Credential values remain in <code>sdk.secrets</code>; Account/Console surfaces expose metadata only.</li></ul><p>These surfaces are <strong>reserved</strong> — they exist as stubs and throw <code>NotImplementedError</code> (or in <code>sdk.billing</code>&#39;s case, <code>EntitlementRequiredError</code>). Their shape may change before they ship:</p><ul><li><code>sdk.events</code> — reserved post-v1 surface.</li><li><code>sdk.billing</code> — plugin monetization (RFC 0003). <code>getEntitlement(pluginId)</code> and <code>requireEntitlement(pluginId)</code> are exported as stubs; <code>EntitlementRequiredError</code> is exported. The platform&#39;s own paywall gating (middleware redirect + license token import) does not require calling <code>sdk.billing</code> directly — it is available for plugins that want to do entitlement-aware rendering inside a partially-gated surface.</li></ul><p>When one of these is implemented, it graduates into the stable surface with a <strong>minor</strong> release (additive), and this document is updated.</p><h2 id="distribution" tabindex="-1">Distribution <a class="header-anchor" href="#distribution" aria-label="Permalink to &quot;Distribution&quot;">​</a></h2><p><code>@sovereignfs/sdk</code> is a <strong>types-first contract</strong> with <strong>zero runtime dependencies</strong>. Implementations are host-provided by the Sovereign runtime at startup (<code>runtime/instrumentation.ts</code> registers them via <code>provideHost()</code>); when the SDK is called from a composed plugin route, the host&#39;s copy always executes, not the caller&#39;s installed copy.</p><p>This means:</p><ul><li>A standalone plugin repo can install <code>@sovereignfs/sdk</code> as a devDependency and type-check against its surface without pulling in platform-internal packages (<code>@sovereignfs/db</code>, <code>@sovereignfs/mailer</code>, etc. — those stay <code>private</code> and are never bundled into the published SDK).</li><li>The SDK&#39;s methods are not meaningful outside the runtime. Calling them from a process with no registered host throws <code>&quot;@sovereignfs/sdk: no runtime host is registered&quot;</code>. The dev/test loop is always runtime-hosted.</li></ul><p>See <code>docs/plugin-development.md</code> → <a href="#plugin-isolation-boundary">Plugin isolation boundary</a> for the full authoring ✅ / build ❌ / run ❌ table.</p><h2 id="published-packages-summary" tabindex="-1">Published packages summary <a class="header-anchor" href="#published-packages-summary" aria-label="Permalink to &quot;Published packages summary&quot;">​</a></h2><p>Three packages from this monorepo are published to npm:</p><table tabindex="0"><thead><tr><th>Package</th><th>Purpose</th><th>Policy</th></tr></thead><tbody><tr><td><code>@sovereignfs/sdk</code></td><td>Plugin↔platform contract (types)</td><td>Strict semver (this document)</td></tr><tr><td><code>@sovereignfs/ui</code></td><td>Design system (components + tokens)</td><td>Same strict semver as SDK (NFR-04)</td></tr><tr><td><code>@sovereignfs/create-plugin</code></td><td>CLI scaffolding tool</td><td>Semver; CLI tools follow patch/minor/major but have no library compatibility obligation</td></tr></tbody></table><p><code>@sovereignfs/create-plugin</code> is invoked via <code>npm create @sovereignfs/plugin</code>. It is a dev tool, not a runtime library — plugin code never imports it, so breaking changes follow standard semver without the additional &quot;patch must never break&quot; constraint that applies to sdk and ui.</p>',25)])])}const g=t(s,[["render",d]]);export{u as __pageData,g as default};
